import{_ as t,c as a,o as l,aP as r}from"./chunks/framework.CcVWUnOI.js";const v=JSON.parse('{"title":"vue3","description":"","frontmatter":{},"headers":[],"relativePath":"frontEnd/vue/vue3.md","filePath":"frontEnd/vue/vue3.md","lastUpdated":1776582100000}'),i={name:"frontEnd/vue/vue3.md"};function d(o,e,u,n,c,h){return l(),a("div",null,e[0]||(e[0]=[r('<h1 id="vue3" tabindex="-1">vue3 <a class="header-anchor" href="#vue3" aria-label="Permalink to &quot;vue3&quot;">​</a></h1><h2 id="vue3和vue2的区别" tabindex="-1">vue3和vue2的区别 <a class="header-anchor" href="#vue3和vue2的区别" aria-label="Permalink to &quot;vue3和vue2的区别&quot;">​</a></h2><ul><li>双向数据绑定的原理不同</li><li>是否支持碎片</li><li>API不同</li><li>定义数据变量方法不同</li><li>生命周期的不同</li><li>传值不同</li><li>指令和插槽不同</li><li>main.js不同</li></ul><h2 id="vue3的性能为什么比vue2好" tabindex="-1">vue3的性能为什么比vue2好？ <a class="header-anchor" href="#vue3的性能为什么比vue2好" aria-label="Permalink to &quot;vue3的性能为什么比vue2好？&quot;">​</a></h2><ul><li>diff算法的优化</li><li>静态提升</li><li>事件侦听缓存</li></ul><h2 id="vue3为什么使用proxy" tabindex="-1">vue3为什么使用Proxy <a class="header-anchor" href="#vue3为什么使用proxy" aria-label="Permalink to &quot;vue3为什么使用Proxy&quot;">​</a></h2><ul><li>proxy可以代理整个对象，defineProperty只代理对象上的某个属性</li><li>proxy对代理对象的监听更加丰富</li><li>proxy代理对象会生成新的对象，不会修改被代理对象本身</li><li>proxy补兼容ie浏览器</li></ul><h2 id="reactive-解构" tabindex="-1">reactive+解构 <a class="header-anchor" href="#reactive-解构" aria-label="Permalink to &quot;reactive+解构&quot;">​</a></h2><p>用es6解构reactive对象得到的是原始值的副本，脱离了响应式系统，因此后续修改不会触发视图更新。Vue3的Proxy只能拦截对对象属性的访问和修改，结构时是浅拷贝、而不是引用拷贝。</p><ul><li>不要解构，直接使用响应式对象属性</li><li>toRefs转成ref对象</li><li>用ref，而不是reactive</li></ul><h2 id="数组更新" tabindex="-1">数组更新 <a class="header-anchor" href="#数组更新" aria-label="Permalink to &quot;数组更新&quot;">​</a></h2><p>可以用<code>a[1] = 999</code>，但是为什么还推荐使用<code>a.splice(1, 1, 999)</code></p><ul><li>vue2迁移项目，vue2中不能通过索引更新</li><li>splice 是原子操作，Vue 可以更好地批量收集依赖和触发更新</li></ul><h2 id="vue3-ref为什么要-value" tabindex="-1">Vue3 ref为什么要.value <a class="header-anchor" href="#vue3-ref为什么要-value" aria-label="Permalink to &quot;Vue3 ref为什么要.value&quot;">​</a></h2><ul><li>JS 中基础类型无法被 Proxy 代理，必须用对象包裹</li><li>ref 本质就是一个 <code>{value: 原始值}</code> 的响应式对象</li><li>所以修改和访问时，必须通过 <code>.value</code></li><li>在模板中会自动解构，所以不用写 <code>.value</code></li></ul><h2 id="render-函数主要做这几件事" tabindex="-1"><code>render</code> 函数主要做这几件事： <a class="header-anchor" href="#render-函数主要做这几件事" aria-label="Permalink to &quot;`render` 函数主要做这几件事：&quot;">​</a></h2><ol><li><strong>生成虚拟节点 VNode</strong>：基于组件的 props、响应式数据，通过 h / createVNode 描述 DOM 结构，不直接操作真实 DOM。</li><li><strong>交给渲染器做 Diff</strong>：数据更新时重新执行 render 得到新 VNode，渲染器对比新旧 VNode，最小化更新 DOM。</li><li><strong>实现跨平台渲染</strong>：Vue 运行时核心与平台操作分离，render 只负责描述结构，让 Vue 能渲染到 web、小程序、canvas 等环境。</li><li><strong>模板最终都会编译成 render</strong>：我们写的 <code>&lt;template&gt;</code> 本质上会被编译器优化后生成 render 函数，执行逻辑一致。</li></ol><h2 id="watch-和-watcheffect-的核心区别" tabindex="-1">watch 和 watchEffect 的核心区别： <a class="header-anchor" href="#watch-和-watcheffect-的核心区别" aria-label="Permalink to &quot;watch 和 watchEffect 的核心区别：&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>watch</th><th>watchEffect</th></tr></thead><tbody><tr><td>依赖监听</td><td>手动指定要监听的数据源</td><td>自动追踪内部响应式依赖</td></tr><tr><td>初始执行</td><td>惰性执行，默认初始不触发</td><td>立即执行一次，再监听变化</td></tr><tr><td>新旧值</td><td>可同时获取 newValue、oldValue</td><td>只能获取当前最新值，无旧值</td></tr><tr><td>依赖清晰度</td><td>依赖明确，可读性高</td><td>依赖隐式，复杂场景不易追踪</td></tr><tr><td>执行时机</td><td>默认在 DOM 更新后执行</td><td>默认在 DOM 更新前执行</td></tr><tr><td>适用场景</td><td>需监听特定值、需要旧值、异步逻辑</td><td>依赖多且不确定、需初始化执行、简单联动</td></tr><tr><td>停止监听</td><td>返回函数可手动停止</td><td>同样返回函数可手动停止</td></tr><tr><td>配置项</td><td>支持 immediate、deep、flush 等</td><td>支持 flush、onTrack 等</td></tr></tbody></table><h2 id="如何解决跨域" tabindex="-1">如何解决跨域 <a class="header-anchor" href="#如何解决跨域" aria-label="Permalink to &quot;如何解决跨域&quot;">​</a></h2><ul><li>CORS（后端配置）</li><li>前端代理服务器（proxy） <ul><li>前端请求 → 先发给本地代理服务器 → 去请求目标后端接口（服务器之间通信，无跨域）</li></ul></li><li>Nginx 反向代理</li><li>jsonp（后端配置）</li></ul>',21)]))}const f=t(i,[["render",d]]);export{v as __pageData,f as default};
